    // dp[i] stores a map/vector representing counts for the i-th position.
    // Since the number of candidates can be up to 5001, and N is up to 1000,
    // a full 2D array might be too large if we index by the candidate index.

    // Let's refine the state based on the structure of the problem:
    // dp[i][j]: The number of valid arrays of length i+1 such that arr[i] is the j-th candidate number
    // for digitSum[i].

    // dp[i] will store the counts for the i-th element.
    // dp[i][j] = count.
    vector<vector<long long>> dp(n);

    // Base case: i = 0 (First element)
    const vector<int>* list0 = candidate_lists[0];
    int size0 = list0->size();
