        // Iterate over all candidates for arr[i] (j-th candidate)
        for (int j = 0; j < size_i; ++j) {
            int current_val = (*list_i)[j];
            long long current_count = 0;

            // Iterate over all candidates for arr[i-1] (k-th candidate)
            // Condition: arr[i-1] <= arr[i]
            for (int k = 0; k < list_prev->size(); ++k) {
                int prev_val = (*list_prev)[k];

                if (prev_val <= current_val) {
                    // Add the count of valid prefixes ending at arr[i-1] = prev_val
                    current_count = (current_count + dp[i-1][k]) % MOD;
                }
            }
            dp[i][j] = current_count;
        }
    }

    // Final result: Sum up all counts in the last DP layer
    long long total_count = 0;
    if (n > 0) {
        int last_idx = n - 1;
        for (long long count : dp[last_idx]) {
            total_count = (total_count + count) % MOD;
        }
    }

    return total_count;
