typedef long long ll;

const int MOD = 1e9 + 7;
const int MAX_VAL = 5000;

// Function to calculate the sum of digits of a number
int sum_digits(int n) {
    int sum = 0;
    while (n > 0) {
        sum += n % 10;
        n /= 10;
    }
    return sum;
}

// Precompute the set of valid numbers for each required digit sum
// valid_numbers[s] stores all numbers x such that 0 <= x <= 5000 and sum_digits(x) == s.
map<int, vector<int>> precompute_valid_numbers() {
    map<int, vector<int>> valid_numbers;
    for (int i = 0; i <= MAX_VAL; ++i) {
        int s = sum_digits(i);
        valid_numbers[s].push_back(i);
    }
    return valid_numbers;
}

// dp[i][j] will store the number of valid arrays of length i+1
// such that the last element arr[i] is j.
// Since the state space for j (the value of arr[i]) is up to 5000,
// and N is up to 1000, a full DP might be too slow or memory intensive
// if we use the value j directly.

// We should use dynamic programming based on the index i and the *value* of the previous element.

ll solve(vector<ll> digitSum) {
    int n = digitSum.size();
    if (n == 0) return 0;

    map<int, vector<int>> valid_numbers_map = precompute_valid_numbers();

    // dp[i] will be a map: {value_of_arr[i] -> count}
    // Since we only need dp[i-1] to compute dp[i], we can optimize space.

    // dp_prev: map<int, ll> stores {value -> count} for the previous index (i-1)
    // dp_curr: map<int, ll> stores {value -> count} for the current index (i)

    // Base case: i = 0
    int target_sum_0 = digitSum[0];
    ll total_count = 0;
    map<int, ll> dp_prev; // For index 0

    if (valid_numbers_map.count(target_sum_0)) {
        for (int val : valid_numbers_map[target_sum_0]) {
            dp_prev[val] = 1;
            total_count = (total_count + 1) % MOD;
        }
    } else {
        return 0; // No number satisfies the first condition
    }

    // Iterate from i = 1 to n-1
    for (int i = 1; i < n; ++i) {
        int target_sum_i = digitSum[i];
        map<int, ll> dp_curr;
        ll current_total = 0;

        if (!valid_numbers_map.count(target_sum_i)) {
            return 0; // No number satisfies the current condition
        }

        const auto& valid_list_i = valid_numbers_map[target_sum_i];

        // For each possible value v_i for arr[i]
        for (int v_i : valid_list_i) {
            ll count_for_v_i = 0;

            // We need to sum up counts from dp_prev for all v_{i-1} such that v_{i-1} <= v_i

            // Iterate over all entries in dp_prev (which stores {v_{i-1} -> count})
            for (const auto& pair : dp_prev) {
                int v_prev = pair.first;
                ll count_prev = pair.second;

                if (v_prev <= v_i) {
                    count_for_v_i = (count_for_v_i + count_prev) % MOD;
                }
            }

            if (count_for_v_i > 0) {
                dp_curr[v_i] = count_for_v_i;
                current_total = (current_total + count_for_v_i) % MOD;
            }
        }

        dp_prev = dp_curr;
        if (dp_prev.empty()) {
            return 0; // No valid continuation found
        }
    }

    return total_count;
}
